458→    public function extractSlots(Request $request): JsonResponse
459→    {
460→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
461→        if (!$this->inWhitelist($sfuserId)) {
462→            \Log::info('[lbl][0416-AI日报][AiSlots] 无权限', ['sfuser_id' => $sfuserId]);
463→            return $this->responseJsonFail('无权限');
464→        }
465→
466→        $message = $request->input('message');
467→        $conversationId = $request->input('conversation_id', '');
468→        $availableGroups = $request->input('available_groups', []);
469→        $availableMembers = $request->input('available_members', []);
470→        $previousContext = $request->input('previous_context');
471→        $hasExistingContext = $request->boolean('has_existing_context', false);
472→
473→        // 将可用分组和成员列表格式化为 prompt 中的列表
474→        $groupList = !empty($availableGroups)
475→            ? implode("\n", array_map(fn ($g) => "   - {$g}", $availableGroups))
476→            : '   - （无可用分组）';
477→        $memberList = !empty($availableMembers)
478→            ? implode('、', $availableMembers)
479→            : '（无可用成员列表）';
480→        // 上次查询上下文：首次查询时为"无"，续查时包含上次的成员和周期
481→        $prevCtx = '无（首次查询）';
482→        if (!empty($previousContext)) {
483→            $prevMembers = implode('、', $previousContext['members'] ?? []);
484→            $prevType = ($previousContext['member_type'] ?? '') === 'group' ? '分组' : '成员';
485→            $prevPeriod = ($previousContext['period_start'] ?? '').' ~ '.($previousContext['period_end'] ?? '');
486→            $prevCtx = "上次查询{$prevType}：{$prevMembers}，周期：{$prevPeriod}";
487→        }
488→        $hasContextLabel = $hasExistingContext ? '是' : '否';
489→        $systemPrompt = sprintf(self::SLOT_EXTRACTION_PROMPT, $hasContextLabel, $groupList, $memberList, now()->toDateString(), $prevCtx);
490→
491→        \Log::info('[lbl][0416-AI日报][AiSlots] request', [
492→            'sfuser_id' => $sfuserId,
493→            'message' => $message,
494→            'previous_context' => $previousContext,
495→            'available_groups' => $availableGroups,
496→            'member_count' => count($availableMembers),
497→        ]);
498→
499→        // 返回 message + ai_analysis_config，由 oa-core TransferRequestService 做 blocking AI 调用
500→        \Log::info('[lbl][0416-AI日报][AiSlots] response', [
501→            'sfuser_id' => $sfuserId,
502→            'message' => $message,
503→            'prompt_len' => mb_strlen($systemPrompt),
504→        ]);
505→        return $this->responseJsonSuccess([
506→            'message' => $message,
507→            'ai_analysis_config' => [
508→                'system_prompt' => $systemPrompt,
509→                'target_field' => 'message',
510→                'output_field' => 'ai_result',
511→            ],
512→        ]);
513→    }
514→
515→    // ----------------------------------------------------------------
516→    // 发送消息（SSE 流式）
517→    // ----------------------------------------------------------------
518→
519→    public function ask(Request $request): JsonResponse
520→    {
521→        $sfuserId = Arr::get($request->input('sfuser_info'), 'id');
522→        if (!$this->inWhitelist($sfuserId)) {
523→            \Log::info('[lbl][0416-AI日报][AiAsk] 无权限', ['sfuser_id' => $sfuserId]);
524→            return $this->responseJsonFail('无权限');
525→        }
526→        $roleId = $request->input('role_id');
527→        $sessionId = $request->input('session_id');
528→        $message = $request->input('message');
529→        $reportContext = $request->input('report_context', '');
530→        $reportContextRaw = $request->input('report_context_raw', '');
531→
532→        // 解压 report_context（前端 gzip+base64 压缩后以 "gz:" 前缀标识）
533→        if (str_starts_with($reportContext, 'gz:')) {
534→            $decoded = base64_decode(substr($reportContext, 3), true);
535→            $reportContext = $decoded !== false ? (gzdecode($decoded) ?: $reportContext) : $reportContext;
536→        }
537→        // 去除多余空白（连续空行压缩为单空行），减少发给 AI 的 token
538→        $reportContext = preg_replace('/\n{3,}/', "\n\n", trim($reportContext));
539→        \Log::info('[lbl][0416-AI日报][AiAsk] report_context size', [
540→            'bytes' => strlen($reportContext),
541→            'chars' => mb_strlen($reportContext),
542→        ]);
543→
544→        // 校验角色归属
545→        $role = DB::table('daily_report_ai_roles')
546→            ->where('id', $roleId)
547→            ->where('sfuser_id', $sfuserId)
548→            ->whereNull('deleted_at')
549→            ->first();
550→
551→        if (!$role) {
552→            return $this->responseJsonFail('角色不存在');
553→        }
554→
555→        // 创建或复用会话
556→        if (!$sessionId) {
557→            $title = mb_substr($message, 0, 20);
558→            $sessionId = DB::table('daily_report_ai_sessions')->insertGetId([
559→                'sfuser_id' => $sfuserId,
560→                'role_id' => $roleId,
561→                'title' => $title,
562→                'created_at' => now(),
563→                'updated_at' => now(),
564→            ]);
565→        } else {
566→            $sessionRow = DB::table('daily_report_ai_sessions')
567→                ->where('id', $sessionId)
568→                ->where('sfuser_id', $sfuserId)
569→                ->whereNull('deleted_at')
570→                ->first();
571→            if (!$sessionRow) {
572→                return $this->responseJsonFail('会话不存在');
573→            }
574→        }
575→
576→        // 解压 report_context_raw（与 report_context 相同的 gzip+base64 压缩格式）
577→        if (str_starts_with($reportContextRaw, 'gz:')) {
578→            $decoded = base64_decode(substr($reportContextRaw, 3), true);
579→            $reportContextRaw = $decoded !== false ? (gzdecode($decoded) ?: $reportContextRaw) : $reportContextRaw;
580→        }
581→
582→        // 保存同步日报上下文（如果有）—— 优先存原始 HTML，便于页面回显
583→        $contextToStore = !empty($reportContextRaw) ? $reportContextRaw : $reportContext;
584→        if (!empty($contextToStore)) {
585→            DB::table('daily_report_ai_messages')->insert([
586→                'session_id' => $sessionId,
587→                'role' => 'context',
588→                'content' => $contextToStore,
589→                'created_at' => now(),
590→            ]);
591→        }
592→
593→        // 保存用户消息
594→        DB::table('daily_report_ai_messages')->insert([
595→            'session_id' => $sessionId,
596→            'role' => 'user',
597→            'content' => $message,
598→            'created_at' => now(),
599→        ]);
600→
601→        // 更新会话时间
602→        DB::table('daily_report_ai_sessions')
603→            ->where('id', $sessionId)
604→            ->update(['updated_at' => now()]);
605→
606→        // 构建发送给 AI 的内容
607→        $queryParts = [];
608→        if (!empty($reportContext)) {
609→            $queryParts[] = "[日报数据]\n{$reportContext}";
610→        }
611→        $queryParts[] = $message;
612→        $query = implode("\n\n---\n\n", $queryParts);
613→
614→        \Log::info('[lbl][0416-AI日报][AiAsk] request', [
615→            'session' => $sessionId,
616→            'query_len' => mb_strlen($query),
617→        ]);
618→
619→        // 返回 query + session_id，AI streaming 由 oa-core TransferRequestService 完成
620→        return $this->responseJsonSuccess([
621→            'query' => $query,
622→            'session_id' => $sessionId,
623→        ]);
624→    }
625→
626→    // ----------------------------------------------------------------
627→    // AI 连通性测试
628→    // ----------------------------------------------------------------
629→
630→    /**
631→     * Blocking 模式测试：oa-core TransferRequestService 做 blocking AI 调用，结果写入 output_field.
632→     */
633→    public function aiTestBlocking(Request $request): JsonResponse
634→    {
635→        $message = $request->input('message', 'say hi');
636→        $systemPrompt = $request->input('system_prompt', '你是一个测试助手，简短回复即可。');
637→
638→        \Log::info('[lbl][0416-AI日报][AiTest] blocking test', [
639→            'message' => $message,
640→            'prompt_len' => mb_strlen($systemPrompt),
641→        ]);
642→
643→        return $this->responseJsonSuccess([
644→            'message' => $message,
645→            'ai_analysis_config' => [
646→                'system_prompt' => $systemPrompt,
647→                'target_field' => 'message',
648→                'output_field' => 'ai_result',
649→            ],
650→        ]);
651→    }
652→
653→    /**
654→     * Streaming 模式测试：oa-core TransferRequestService 做 streaming AI 调用，SSE 输出.
655→     */
656→    public function aiTestStream(Request $request): JsonResponse
657→    {
658→        $message = $request->input('message', 'say hi');
659→        $systemPrompt = $request->input('system_prompt', '你是一个测试助手，简短回复即可。');
660→
661→        \Log::info('[lbl][0416-AI日报][AiTest] streaming test', [
662→            'message' => $message,
663→            'prompt_len' => mb_strlen($systemPrompt),
664→        ]);
665→
666→        return $this->responseJsonSuccess([
667→            'content' => $message,
668→            'ai_analysis_config' => [
669→                'system_prompt' => $systemPrompt,
670→                'target_field' => 'content',
671→            ],
672→        ]);
673→    }
674→
675→    private function inWhitelist(int $sfuserId): bool
676→    {
677→        $setting = OaSetting::where('type', 'daily_report_ai')->select('ids', 'is_on')->first();
678→        $result = $setting && $setting->is_on && in_array($sfuserId, $setting->ids ?? []);
679→        if (!$result) {
680→            \Log::info('[lbl][0416-AI日报][Whitelist] denied', [
681→                'sfuser_id' => $sfuserId,
682→                'has_setting' => !empty($setting),
683→                'is_on' => $setting->is_on ?? null,
684→                'ids' => $setting->ids ?? null,
685→            ]);
686→        }
687→        return $result;
688→    }
689→}
