        $respData = &$resp['data'];
        // 响应中有 decrypt_config 的话，与请求中的 decrypt_config 合并（相同键名以响应中的为准）
        $decrypt_config = empty($respData['decrypt_config']) ? $decrypt_config : array_merge($decrypt_config ?? [], $respData['decrypt_config']);
        if (isset($respData['decrypt_config'])) {
            unset($respData['decrypt_config']);
        }
        if (!empty($decrypt_config)) {
            $respData = DecryptService::app()->decryptData($respData, $decrypt_config, $decrypt_config['operation'] ?? 'response');
        }

        // 合并响应中的 ai_analysis_config（oa-server 可在响应中提供/覆盖 AI 配置）
        if (!empty($respData['ai_analysis_config'])) {
            $ai_analysis_config = array_merge($ai_analysis_config ?? [], $respData['ai_analysis_config']);
            unset($respData['ai_analysis_config']);
        }

        // AI 分析（解密之后执行，仅当 ai_analysis_config 存在时）
        if (!empty($ai_analysis_config) && !empty($ai_analysis_config['system_prompt'])) {
            $targetField = $ai_analysis_config['target_field'] ?? null;
            $outputField = $ai_analysis_config['output_field'] ?? 'ai_analysis';
