532→                        'error' => $jsonErr['error'],
533→                    ]);
534→                }
535→                // 空回复但 HTTP 200，可能是解析问题，不重试
536→                return '';
537→            }
538→
539→            Log::info('[lbl][0416-AI日报][AiAnalysis][VertexAI] streaming done', [
540→                'http_code' => $httpCode,
541→                'reply_len' => mb_strlen($fullReply),
542→                'attempt' => $attempt,
543→            ]);
544→
545→            return $fullReply;
546→        }
547→
548→        Log::error('[lbl][0416-AI日报][AiAnalysis][VertexAI] streaming all {max} attempts failed', ['max' => $maxRetries]);
549→        return '';
550→    }
551→
552→    /**
553→     * 指数退避 + 随机 jitter，上限 60 秒。
554→     * delay = min(baseDelay * 2^attempt + jitter, 60).
555→     */
556→    private function retrySleep(int $baseDelay, int $attempt): void
557→    {
558→        $delay = min($baseDelay * (2 ** $attempt) + random_int(0, 3), 60);
559→        Log::info('[lbl][0416-AI日报][AiAnalysis][VertexAI] retry sleep', ['delay' => $delay, 'attempt' => $attempt]);
560→        sleep($delay);
561→    }
562→
563→    /**
564→     * 构建 Vertex AI 的 endpoint URL 和 model。
565→     */
566→    private function getVertexAiEndpoint(): array
567→    {
568→        $projectId = config('vertex_ai.project_id');
569→        $location = config('vertex_ai.location', 'us-central1');
570→        $model = config('vertex_ai.model', 'google/gemini-2.5-flash');
571→        $endpoint = "https://{$location}-aiplatform.googleapis.com/v1beta1/projects/{$projectId}/locations/{$location}/endpoints/openapi/chat/completions";
572→
573→        return [$endpoint, $model];
574→    }
575→
576→    /**
577→     * 通过 GCE Metadata Server 获取 Service Account 的 access token。
578→     */
579→    private function getAccessToken(): string
580→    {
581→        $url = 'http://metadata.google.internal/computeMetadata/v1/instance/service-accounts/default/token';
582→        $context = stream_context_create([
583→            'http' => [
584→                'header' => 'Metadata-Flavor: Google',
585→                'timeout' => 5,
586→            ],
587→        ]);
588→
589→        $response = @file_get_contents($url, false, $context);
590→        if ($response === false) {
591→            Log::error('[lbl][0416-AI日报][AiAnalysis] failed to get access token from metadata server');
592→            return '';
593→        }
594→
595→        $data = json_decode($response, true);
596→        return $data['access_token'] ?? '';
597→    }
598→}
