private async sendExtractSlots(text: string) {
    const limitAction = await this.checkContextOverLimit()
    if (limitAction === 'newSession') { this.newSession(); return }
    if (limitAction === 'abort') { return }

    this.messages.push({ role: 'user', content: text })
    this.pendingSlotMessages.push({ role: 'user', content: text })
    this.inputText = ''
    this.$nextTick(this.scrollToBottom)

    const assistantIdx = this.messages.length
    this.messages.push({ role: 'assistant', content: '' })
    this.isStreaming = true

    try {
        // 收集可用分组名和所有成员花名
        const availableGroups = this.groupOptions.map(g => g.label)
        const availableMembers = [...new Set(this.groupOptions.flatMap(g => g.value))].filter(Boolean)
        // 续查模式：传入上次的槽位结果
        const previousContext = this.lastSlotResult ? {
            member_type: this.lastSlotResult.member_type,
            members: this.lastSlotResult.members,
            period_start: this.lastSlotResult.period_start,
            period_end: this.lastSlotResult.period_end,
        } : undefined
        const hasExistingContext = this.messages.some(m => m.role === 'context')
        const result = await dailyReportAiApis.extractSlots({
            message: text,
            conversation_id: this.slotsConversationId || undefined,
            has_existing_context: hasExistingContext || undefined,
            available_groups: availableGroups,
            available_members: availableMembers,
            previous_context: previousContext,
        })

        if (!result) {
            this.messages[assistantIdx].content = this.$t('aiChat.errorMsg') as string
            this.pendingSlotMessages.push({ role: 'assistant', content: this.messages[assistantIdx].content })
            await this.flushSlotMessages()
            return

